proof_block:
// The ensures of the original `iommu_table_map_4k_page` is duplicated under
// the synthetic det fn for `post1_self_` and `post2_self_`. Every forall in
// the ensures is `#![trigger]`-protected on a single side (e.g. only
// `post1_self_.ioid_active(p)`), so z3 instantiates the two foralls at
// disjoint ground terms and never lines them up to discharge
// `det_iommu_table_map_4k_page_equal`. The prelude below
//   (a) re-instantiates each forall ensures *separately* for post1 / post2
//       with the original single-side triggers so both sides land in the
//       e-graph along the same path;
//   (b) chains the stable struct-field ensures `post*_self_.X =~= pre_self_.X`
//       through `pre_self_` so the cross-run `==` conjuncts of the equal-fn
//       become visible without quantifier matching;
//   (c) closes the per-pcid / per-ioid spec-fn equalities cross-run via
//       bridge `forall|...|` assertions that carry both-side triggers, then
//       case-splits the only target-specific spec fn
//       `get_iommu_table_mapping_by_ioid` on `p == target_ioid`.

// --- (a) Re-instantiate the trigger-protected ensures foralls per run. ---

// pcid_active: post*_self_.pcid_active(p) == pre_self_.pcid_active(p)
assert(forall|p: Pcid|
    #![trigger post1_self_.pcid_active(p)]
    post1_self_.pcid_active(p) == pre_self_.pcid_active(p));
assert(forall|p: Pcid|
    #![trigger post2_self_.pcid_active(p)]
    post2_self_.pcid_active(p) == pre_self_.pcid_active(p));

// pcid_to_proc_ptr (gated on pcid_active).
assert(forall|p: Pcid|
    #![trigger post1_self_.pcid_active(p)]
    #![trigger post1_self_.pcid_to_proc_ptr(p)]
    post1_self_.pcid_active(p)
        ==> pre_self_.pcid_to_proc_ptr(p) == post1_self_.pcid_to_proc_ptr(p));
assert(forall|p: Pcid|
    #![trigger post2_self_.pcid_active(p)]
    #![trigger post2_self_.pcid_to_proc_ptr(p)]
    post2_self_.pcid_active(p)
        ==> pre_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p));

// ioid_active: post*_self_.ioid_active(i) == pre_self_.ioid_active(i)
assert(forall|i: IOid|
    #![trigger post1_self_.ioid_active(i)]
    post1_self_.ioid_active(i) == pre_self_.ioid_active(i));
assert(forall|i: IOid|
    #![trigger post2_self_.ioid_active(i)]
    post2_self_.ioid_active(i) == pre_self_.ioid_active(i));

// ioid_to_proc_ptr (gated on ioid_active).
assert(forall|i: IOid|
    #![trigger post1_self_.ioid_active(i)]
    #![trigger post1_self_.ioid_to_proc_ptr(i)]
    post1_self_.ioid_active(i)
        ==> pre_self_.ioid_to_proc_ptr(i) == post1_self_.ioid_to_proc_ptr(i));
assert(forall|i: IOid|
    #![trigger post2_self_.ioid_active(i)]
    #![trigger post2_self_.ioid_to_proc_ptr(i)]
    post2_self_.ioid_active(i)
        ==> pre_self_.ioid_to_proc_ptr(i) == post2_self_.ioid_to_proc_ptr(i));

// get_iommu_table_mapping_by_ioid for off-target, active ioid.
assert(forall|p: IOid|
    #![trigger post1_self_.ioid_active(p)]
    #![trigger post1_self_.get_iommu_table_mapping_by_ioid(p)]
    post1_self_.ioid_active(p) && p != target_ioid
        ==> pre_self_.get_iommu_table_mapping_by_ioid(p)
              == post1_self_.get_iommu_table_mapping_by_ioid(p));
assert(forall|p: IOid|
    #![trigger post2_self_.ioid_active(p)]
    #![trigger post2_self_.get_iommu_table_mapping_by_ioid(p)]
    post2_self_.ioid_active(p) && p != target_ioid
        ==> pre_self_.get_iommu_table_mapping_by_ioid(p)
              == post2_self_.get_iommu_table_mapping_by_ioid(p));

// get_pagetable_mapping_by_pcid for active pcid.
assert(forall|p: Pcid|
    #![trigger post1_self_.pcid_active(p)]
    #![trigger post1_self_.get_pagetable_mapping_by_pcid(p)]
    post1_self_.pcid_active(p)
        ==> pre_self_.get_pagetable_mapping_by_pcid(p)
              == post1_self_.get_pagetable_mapping_by_pcid(p));
assert(forall|p: Pcid|
    #![trigger post2_self_.pcid_active(p)]
    #![trigger post2_self_.get_pagetable_mapping_by_pcid(p)]
    post2_self_.pcid_active(p)
        ==> pre_self_.get_pagetable_mapping_by_pcid(p)
              == post2_self_.get_pagetable_mapping_by_pcid(p));

// --- (b) Cross-run equalities for the stable struct fields, chained
//         through `pre_self_` via the `=~=` ensures.                  ---

assert(post1_self_.kernel_entries =~= post2_self_.kernel_entries);
assert((post1_self_.kernel_entries_ghost)@ =~= (post2_self_.kernel_entries_ghost)@);
assert(post1_self_.free_pcids =~= post2_self_.free_pcids);
assert(post1_self_.page_tables =~= post2_self_.page_tables);
assert((post1_self_.page_table_pages)@ =~= (post2_self_.page_table_pages)@);
assert(post1_self_.free_ioids =~= post2_self_.free_ioids);
assert((post1_self_.iommu_table_pages)@ =~= (post2_self_.iommu_table_pages)@);
assert(post1_self_.root_table =~= post2_self_.root_table);
assert((post1_self_.root_table_cache)@ =~= (post2_self_.root_table_cache)@);
assert(post1_self_.pci_bitmap =~= post2_self_.pci_bitmap);

// The equal-fn checks the `.view()` of root_table and pci_bitmap, which are
// implied by the struct-level `=~=` above (both are simple field-wise views).
assert(post1_self_.root_table.view() == post2_self_.root_table.view());
assert(post1_self_.pci_bitmap.view() == post2_self_.pci_bitmap.view());

// --- (c) Bridge foralls combining both runs, on the per-pcid / per-ioid
//         spec fns. Each bridge fires with *either* post1 or post2 as the
//         ground trigger, so the equal-fn's quantifier-free obligations
//         pick up the cross-run equality regardless of which side z3 sees
//         first.                                                          ---

// pcid_active matches across runs.
assert forall|p: Pcid|
    #![trigger post1_self_.pcid_active(p)]
    #![trigger post2_self_.pcid_active(p)]
    post1_self_.pcid_active(p) == post2_self_.pcid_active(p)
by {
    // Each side collapses to pre_self_.pcid_active(p) via the per-run
    // forall above.
}

// ioid_active matches across runs.
assert forall|i: IOid|
    #![trigger post1_self_.ioid_active(i)]
    #![trigger post2_self_.ioid_active(i)]
    post1_self_.ioid_active(i) == post2_self_.ioid_active(i)
by {
    // Both sides collapse to pre_self_.ioid_active(i).
}

// pcid_to_proc_ptr matches across runs whenever (either side is) active.
assert forall|p: Pcid|
    #![trigger post1_self_.pcid_to_proc_ptr(p)]
    #![trigger post2_self_.pcid_to_proc_ptr(p)]
    post1_self_.pcid_active(p)
        ==> post1_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p)
by {
    // The pcid_active bridge transfers activeness to post2; the per-run
    // ensures then collapse `*.pcid_to_proc_ptr(p)` to
    // `pre_self_.pcid_to_proc_ptr(p)` on each side.
}

// ioid_to_proc_ptr matches across runs whenever (either side is) active.
assert forall|i: IOid|
    #![trigger post1_self_.ioid_to_proc_ptr(i)]
    #![trigger post2_self_.ioid_to_proc_ptr(i)]
    post1_self_.ioid_active(i)
        ==> post1_self_.ioid_to_proc_ptr(i) == post2_self_.ioid_to_proc_ptr(i)
by {
    // Symmetric to the pcid_to_proc_ptr bridge.
}

// get_pagetable_mapping_by_pcid matches across runs when active.
assert forall|p: Pcid|
    #![trigger post1_self_.get_pagetable_mapping_by_pcid(p)]
    #![trigger post2_self_.get_pagetable_mapping_by_pcid(p)]
    post1_self_.pcid_active(p)
        ==> post1_self_.get_pagetable_mapping_by_pcid(p)
              == post2_self_.get_pagetable_mapping_by_pcid(p)
by {
    // pcid_active bridge transfers to post2; both runs collapse to
    // pre_self_.get_pagetable_mapping_by_pcid(p).
}

// --- target_ioid specialisation: both runs equal the same `pre.insert(...)`.
let target_va = spec_index2va((target_l4i, target_l3i, target_l2i, target_l1i));

assert(post1_self_.get_iommu_table_mapping_by_ioid(target_ioid)
    == pre_self_.get_iommu_table_mapping_by_ioid(target_ioid)
        .insert(target_va, target_entry));
assert(post2_self_.get_iommu_table_mapping_by_ioid(target_ioid)
    == pre_self_.get_iommu_table_mapping_by_ioid(target_ioid)
        .insert(target_va, target_entry));
assert(post1_self_.get_iommu_table_mapping_by_ioid(target_ioid)
    == post2_self_.get_iommu_table_mapping_by_ioid(target_ioid));

// get_iommu_table_mapping_by_ioid matches across runs for any active ioid:
// either it's target_ioid (both sides land on the same `pre.insert(...)`),
// or it's a non-target active ioid (both sides collapse to the same
// `pre.get_iommu_table_mapping_by_ioid(p)` via the off-target ensures).
assert forall|p: IOid|
    #![trigger post1_self_.get_iommu_table_mapping_by_ioid(p)]
    #![trigger post2_self_.get_iommu_table_mapping_by_ioid(p)]
    post1_self_.ioid_active(p)
        ==> post1_self_.get_iommu_table_mapping_by_ioid(p)
              == post2_self_.get_iommu_table_mapping_by_ioid(p)
by {
    if p == target_ioid {
        // Both equal pre.get_iommu_table_mapping_by_ioid(target_ioid)
        //                .insert(target_va, target_entry).
    } else {
        // ioid_active bridge gives post2.ioid_active(p); off-target ensures
        // collapse both to pre.get_iommu_table_mapping_by_ioid(p).
    }
}
